import { tr } from '../utils/translations.js';

const MALE_PHOTO = "data:image/jpeg;base64,";
const FEMALE_PHOTO = "data:image/jpeg;base64,";

export default function GenderStep({ value, onChange, onNext, language, setLanguage }) {
  const isRtl = language === 'fa';

  const s = {
    wrap: {
      width: '100%', height: '100%',
      background: '#0a0a0a',
      display: 'flex', flexDirection: 'column',
      fontFamily: "'Vazirmatn', Tahoma, sans-serif",
      direction: isRtl ? 'rtl' : 'ltr',
      overflow: 'hidden',
    },
    header: {
      padding: '48px 28px 16px',
      flexShrink: 0,
      position: 'relative',
    },
    langSwitch: {
      position: 'absolute', top: 16, left: 28,
      display: 'flex',
      background: 'rgba(255,255,255,0.07)',
      border: '1px solid rgba(255,255,255,0.12)',
      borderRadius: 20, padding: 3,
      direction: 'ltr',
      zIndex: 10,
    },
    langBtn: (active) => ({
      background: active ? '#fff' : 'none', border: 'none',
      fontFamily: "'Vazirmatn', Tahoma, sans-serif",
      fontSize: 11, fontWeight: 700,
      color: active ? '#000' : 'rgba(255,255,255,0.35)',
      cursor: 'pointer', padding: '4px 10px', borderRadius: 14,
      transition: 'background .2s, color .2s',
    }),
    stepLabel: {
      fontSize: 11, fontWeight: 600, color: 'rgba(255,255,255,0.3)',
      letterSpacing: 2, textTransform: 'uppercase', marginBottom: 8,
    },
    progressBar: {
      width: '100%', height: 2,
      background: 'rgba(255,255,255,0.08)', borderRadius: 2, marginBottom: 18,
    },
    progressFill: {
      height: '100%', width: '20%', background: '#fff', borderRadius: 2,
    },
    title: {
      fontSize: 26, fontWeight: 900, color: '#fff',
      lineHeight: 1.2, letterSpacing: -0.5,
    },
    cards: {
      flex: 1, display: 'flex', flexDirection: 'column',
      gap: 10, padding: '0 16px 12px', overflow: 'hidden',
      minHeight: 0,
    },
    card: (selected) => ({
      flex: 1, borderRadius: 18, overflow: 'hidden',
      position: 'relative', cursor: 'pointer',
      border: `2px solid ${selected ? '#c9a84c' : 'transparent'}`,
      transition: 'border-color .22s ease',
    }),
    photo: {
      position: 'absolute', inset: 0,
      width: '100%', height: '100%',
      objectFit: 'cover', objectPosition: 'center top',
      display: 'block',
    },
    overlay: {
      position: 'absolute', inset: 0,
      background: 'linear-gradient(90deg, rgba(0,0,0,0.15) 0%, rgba(0,0,0,0) 100%)',
    },
    checkBadge: (selected) => ({
      position: 'absolute', bottom: 14, right: 14,
      width: 26, height: 26, borderRadius: '50%',
      background: '#c9a84c',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      opacity: selected ? 1 : 0,
      transition: 'opacity .22s ease',
    }),
    ctaWrap: {
      padding: '0 16px 32px', flexShrink: 0,
    },
    btnCta: (active) => ({
      width: '100%', height: 52, borderRadius: 14, border: 'none',
      background: '#fff', color: '#000',
      fontFamily: "'Vazirmatn', Tahoma, sans-serif",
      fontSize: 15, fontWeight: 800,
      cursor: active ? 'pointer' : 'default',
      opacity: active ? 1 : 0.3,
      transition: 'opacity .2s',
    }),
  };

  const canNext = !!value;
  const t = {
    fa: { step: 'مرحله ۱ از ۵', title: 'جنسیت', cta: 'ادامه' },
    en: { step: 'Step 1 of 5',   title: 'Gender',  cta: 'Continue' },
  };
  const txt = t[language] || t.fa;

  return (
    <div style={s.wrap}>
      <div style={s.header}>
        <div style={s.langSwitch}>
          <button style={s.langBtn(language === 'fa')} onClick={() => setLanguage('fa')}>فا</button>
          <button style={s.langBtn(language === 'en')} onClick={() => setLanguage('en')}>En</button>
        </div>
        <div style={s.stepLabel}>{txt.step}</div>
        <div style={s.progressBar}><div style={s.progressFill} /></div>
        <div style={s.title}>{txt.title}</div>
      </div>

      <div style={s.cards}>
        {/* Male card */}
        <div style={s.card(value === 'مرد')} onClick={() => onChange('مرد')}>
          <img style={s.photo} src={MALE_PHOTO} alt="" />
          <div style={s.overlay} />
          <div style={s.checkBadge(value === 'مرد')}>
            <svg width="13" height="13" viewBox="0 0 14 14" fill="none">
              <polyline points="2,7 5.5,10.5 12,3.5" stroke="#000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </div>
        </div>

        {/* Female card */}
        <div style={s.card(value === 'زن')} onClick={() => onChange('زن')}>
          <img style={s.photo} src={FEMALE_PHOTO} alt="" />
          <div style={s.overlay} />
          <div style={s.checkBadge(value === 'زن')}>
            <svg width="13" height="13" viewBox="0 0 14 14" fill="none">
              <polyline points="2,7 5.5,10.5 12,3.5" stroke="#000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </div>
        </div>
      </div>

      <div style={s.ctaWrap}>
        <button style={s.btnCta(canNext)} disabled={!canNext} onClick={onNext}>
          {txt.cta}
        </button>
      </div>
    </div>
  );
}
